static unsigned char convertToDoomKey(unsigned int key)
{
    switch (key)
    {
    case '\r':  // Return key
        key = KEY_ENTER;
        break;
    case 27:    // Escape key
        key = KEY_ESCAPE;
        break;
    case 0x4B:  // Left arrow
        key = KEY_LEFTARROW;
        break;
    case 0x4D:  // Right arrow
        key = KEY_RIGHTARROW;
        break;
    case 0x48:  // Up arrow
        key = KEY_UPARROW;
