{"cmd":"cd /app && node -e "
const fs = require('fs');
const buf = fs.readFileSync('doomgeneric_mips');
// Check ELF header
console.log('Magic:', buf.slice(0,4).toString('hex'));
console.log('Class:', buf[4]);
console.log('Data:', buf[5]);
const readWord = (off) => buf.readUInt32LE(off);
const readHalf = (off) => buf.readUInt16LE(off);
const entry = readWord(24);
const shoff = readWord(32);
const shentsize = readHalf(46);
const shnum = readHalf(48);
const shstrndx = readHalf(50);
console.log('Entry:', '0x' + entry.toString(16));
console.log('Section header offset:', shoff);
console.log('Section header size:', shentsize);
console.log('Number of sections:', shnum);
console.log('SHStrndx:', shstrndx);

// Read section headers
for (let i = 0; i < shnum; i++) {
  const off = shoff + i * shentsize;
  const nameIdx = readWord(off);
  const type = readWord(off+4);
  const flags = readWord(off+8);
  const addr = readWord(off+12);
  const fileOff = readWord(off+16);
  const size = readWord(off+20);
  console.log('Section', i, ': nameIdx=' + nameIdx, 'type=' + type, 'addr=0x' + addr.toString(16), 'fileOff=0x' + fileOff.toString(16), 'size=' + size);
}

// Read shstrtab
const shstrOff = shoff + shstrndx * shentsize;
const shstrFileOff = readWord(shstrOff + 16);
const shstrSize = readWord(shstrOff + 20);
const shstrData = buf.slice(shstrFileOff, shstrFileOff + shstrSize);

// Print section names
for (let i = 0; i < shnum; i++) {
  const off = shoff + i * shentsize;
  const nameIdx = readWord(off);
  let name = '';
  for (let j = nameIdx; j < shstrData.length && shstrData[j] !== 0; j++) {
    name += String.fromCharCode(shstrData[j]);
  }
  console.log('Section', i, ':', name);
}
" 2>&1"}

